const PROCESSING_FEE = 5;

const itemPremium = (item: any): number =>
  item.type === "sword" ? 100 : 0;

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const premium =
      step.items.reduce((sum: number, item: any) => sum + itemPremium(item), 0) +
      PROCESSING_FEE;
    return { premium };
  });
  return { results };
};

